import React, { createContext, useState } from 'react';
import useAudioPlayer from '../hooks/useAudioPlayer';
import { Track } from '../types';

interface AudioContextProps {
  tracks: Track[];
  playTrack: (track: Track) => void;
}

export const AudioContext = createContext<AudioContextProps>({
  tracks: [],
  playTrack: () => {}
});

const AudioProvider: React.FC = ({ children }) => {
  const { playTrack } = useAudioPlayer();
  const [tracks] = useState<Track[]>([
    { title: 'Track 1', artist: 'Artist 1', url: 'https://example.com/track1.mp3' },
    { title: 'Track 2', artist: 'Artist 2', url: 'https://example.com/track2.mp3' },
    { title: 'Track 3', artist: 'Artist 3', url: 'https://example.com/track3.mp3' }
  ]);

  return (
    <AudioContext.Provider value={{ tracks, playTrack }}>
      {children}
    </AudioContext.Provider>
  );
};

export default AudioProvider;
